"use client"

import { useState, useEffect } from "react"
import { Plus, X, Edit2, Package, Ruler, Hash, DollarSign, ChevronRight } from "lucide-react"

interface FabricRoll {
  id?: string;
  code: string;
  name: string;
  metersLeft: number;
  widthCm: number;
  pricePerMeter: number;
  category: string;
  status?: string;
}

export default function InventarioPage() {
  const [rolls, setRolls] = useState<FabricRoll[]>([])
  const [loading, setLoading] = useState(true)
  const [showForm, setShowForm] = useState(false)
  
  const [newRoll, setNewRoll] = useState({
    code: "", name: "", metersLeft: "", widthCm: "", pricePerMeter: "", category: "blackout"
  })

  const fetchInventory = () => {
    setLoading(true)
    fetch("/api/inventory")
      .then(res => res.json())
      .then((data: FabricRoll[]) => {
        setRolls(data)
        setLoading(false)
      })
      .catch(() => setLoading(false))
  }

  useEffect(() => { fetchInventory() }, [])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    const payload = {
      ...newRoll,
      metersLeft: Number(newRoll.metersLeft),
      widthCm: Number(newRoll.widthCm),
      pricePerMeter: Number(newRoll.pricePerMeter),
      status: "in_stock"
    }
    const response = await fetch("/api/inventory", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    })
    if (response.ok) {
      setShowForm(false)
      setNewRoll({ code: "", name: "", metersLeft: "", widthCm: "", pricePerMeter: "", category: "blackout" })
      fetchInventory()
    }
  }

  return (
    <div className="min-h-screen bg-black text-[#f5f0e8] p-3 md:p-6 lg:p-8 pb-24">
      
      {/* HEADER ADAPTABLE */}
      <div className="flex flex-col gap-4 mb-8">
        <div>
          <h2 className="font-serif text-2xl md:text-4xl text-[#c9a961]">Inventario</h2>
          <p className="text-gray-500 text-xs uppercase tracking-widest">AMARIGOM DECO / Stock</p>
        </div>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="w-full sm:w-max flex items-center justify-center gap-2 bg-[#c9a961] text-black px-6 py-4 rounded-sm font-bold text-sm transition-transform active:scale-95"
        >
          {showForm ? <X size={20} /> : <Plus size={20} />}
          {showForm ? "CERRAR" : "AGREGAR ROLLO"}
        </button>
      </div>

      {/* FORMULARIO TIPO MODAL PARA MÓVIL */}
      {showForm && (
        <div className="bg-[#111111] border border-[#c9a961]/20 p-4 md:p-8 mb-8 rounded-sm animate-in fade-in zoom-in duration-300">
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
            {[
              { label: "Código", name: "code", icon: <Hash size={14}/>, type: "text" },
              { label: "Nombre", name: "name", icon: <Package size={14}/>, type: "text" },
              { label: "Metros", name: "metersLeft", icon: <Ruler size={14}/>, type: "number" },
              { label: "Ancho (cm)", name: "widthCm", icon: <Ruler size={14}/>, type: "number" },
              { label: "Precio/m", name: "pricePerMeter", icon: <DollarSign size={14}/>, type: "number" },
            ].map((field) => (
              <div key={field.name} className="flex flex-col gap-1">
                <label className="text-[10px] text-[#c9a961] font-bold uppercase">{field.label}</label>
                <input 
                  type={field.type}
                  step="any"
                  className="bg-black border border-white/10 p-4 rounded-sm text-base focus:border-[#c9a961] outline-none w-full"
                  value={(newRoll as any)[field.name]}
                  onChange={e => setNewRoll({...newRoll, [field.name]: e.target.value})}
                  required
                />
              </div>
            ))}
            <div className="flex flex-col gap-1">
              <label className="text-[10px] text-[#c9a961] font-bold uppercase">Categoría</label>
              <select 
                className="bg-black border border-white/10 p-4 rounded-sm text-base h-[58px]"
                value={newRoll.category}
                onChange={e => setNewRoll({...newRoll, category: e.target.value})}
              >
                <option value="blackout">Blackout</option>
                <option value="sunscreen">Sunscreen</option>
                <option value="tradicional">Tradicional</option>
              </select>
            </div>
            <button type="submit" className="md:col-span-2 lg:col-span-3 bg-[#c9a961] text-black py-4 font-black text-xs tracking-widest uppercase mt-2">
              Confirmar Ingreso
            </button>
          </form>
        </div>
      )}

      {/* VISTA DE LISTADO: MÓVIL (Cards) vs DESKTOP (Tabla) */}
      <div className="mt-4">
        {loading ? (
          <div className="text-center py-20 text-gray-600 animate-pulse uppercase text-xs tracking-widest">Sincronizando...</div>
        ) : (
          <>
            {/* VISTA MÓVIL: Se ve en S9 y Tablets pequeñas */}
            <div className="grid grid-cols-1 gap-3 lg:hidden">
              {rolls.map((roll, i) => (
                <div key={i} className="bg-[#111111] border border-white/5 p-4 rounded-sm flex justify-between items-center shadow-lg">
                  <div className="space-y-1">
                    <div className="flex items-center gap-2">
                        <span className="text-[#c9a961] font-mono text-xs font-bold">{roll.code}</span>
                        <span className="text-[9px] bg-white/5 px-2 py-0.5 rounded-full text-gray-400 uppercase">{roll.category}</span>
                    </div>
                    <h3 className="text-[#f5f0e8] font-medium text-sm">{roll.name}</h3>
                    <p className="text-green-400 font-bold text-lg">{roll.metersLeft} <span className="text-[10px] text-gray-500 font-normal">metros</span></p>
                  </div>
                  <button className="p-4 bg-white/5 rounded-full text-[#c9a961]">
                    <Edit2 size={18} />
                  </button>
                </div>
              ))}
            </div>

            {/* VISTA DESKTOP: Solo se ve en monitores grandes (lg) */}
            <div className="hidden lg:block bg-[#111111] border border-white/5 rounded-sm overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-[#0a0a0a] border-b border-white/10">
                  <tr>
                    <th className="px-6 py-4 text-[10px] font-bold text-gray-500 uppercase tracking-widest">Código</th>
                    <th className="px-6 py-4 text-[10px] font-bold text-gray-500 uppercase tracking-widest">Tela</th>
                    <th className="px-6 py-4 text-[10px] font-bold text-gray-500 uppercase tracking-widest text-right">Stock</th>
                    <th className="px-6 py-4 text-[10px] font-bold text-gray-500 uppercase tracking-widest text-center">Acción</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {rolls.map((roll, i) => (
                    <tr key={i} className="hover:bg-white/[0.02]">
                      <td className="px-6 py-4 text-sm font-mono text-[#c9a961]">{roll.code}</td>
                      <td className="px-6 py-4 text-sm">{roll.name} <span className="text-[10px] text-gray-600 ml-2 uppercase">({roll.category})</span></td>
                      <td className="px-6 py-4 text-sm text-right text-green-400 font-bold">{roll.metersLeft}m</td>
                      <td className="px-6 py-4 text-center">
                        <button className="text-gray-500 hover:text-[#c9a961]"><Edit2 size={16} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </>
        )}
      </div>
    </div>
  )
}